extern "C" {

uintptr_t __stack_chk_guard = static_cast<uintptr_t>(0xa9fff01234);

void __stack_chk_fail(void) {
  LIBC_NAMESPACE::write_to_stderr("stack smashing detected\n");
  LIBC_NAMESPACE::abort();
}

} // extern "C"

